function graceful_shutdown(reason) {
	if (shutdown_timeout_id) return;

	// If a connection was opened with a keep-alive header close() will wait for the connection to
	// time out rather than close it even if it is not handling any requests, so call this first
	httpServer.closeIdleConnections();

	httpServer.close((error) => {
		// occurs if the server is already closed
		if (error) return;

		if (shutdown_timeout_id) {
			clearTimeout(shutdown_timeout_id);
		}
		if (idle_timeout_id) {
			clearTimeout(idle_timeout_id);
		}

		// @ts-expect-error custom events cannot be typed
		process.emit('sveltekit:shutdown', reason);
	});

	shutdown_timeout_id = setTimeout(() => httpServer.closeAllConnections(), shutdown_timeout * 1000);
}

function to_iterator(source, name) {
	// intentionally using `in` because these could be inherited
	if ('next' in source && typeof source.next === 'function') {
		return source;
	}

	if (Symbol.asyncIterator in source && typeof source[Symbol.asyncIterator] === 'function') {
		return source[Symbol.asyncIterator]();
	}

	if (Symbol.iterator in source && typeof source[Symbol.iterator] === 'function') {
		return source[Symbol.iterator]();
	}

	throw new Error(
		`query.live '${name}' must return an Iterator, Iterable, AsyncIterator or AsyncIterable`
	);
}

function has_changed(
	parent_changed,
	route_changed,
	url_changed,
	search_params_changed,
	uses,
	params
) {
	if (force_invalidation) return true;

	if (!uses) return false;

	if (uses.parent && parent_changed) return true;
	if (uses.route && route_changed) return true;
	if (uses.url && url_changed) return true;

	for (const tracked_params of uses.search_params) {
		if (search_params_changed.has(tracked_params)) return true;
	}

	for (const param of uses.params) {
		if (params[param] !== current.params[param]) return true;
	}

	for (const href of uses.dependencies) {
		if (invalidated.some((fn) => fn(new URL(href)))) return true;
	}

	return false;
}

async function server_fallback(url, route, error, status, replace_state) {
	if (url.origin === origin && url.pathname === location.pathname && !hydrated) {
		// We would reload the same page we're currently on, which isn't hydrated,
		// which means no SSR, which means we would end up in an endless loop
		return await load_root_error_page({
			status,
			error,
			url,
			route
		});
	}

	if (DEV && status !== 404) {
		console.error(
			'An error occurred while loading the page. This will cause a full page reload. (This message will only appear during development.)'
		);

		debugger; // eslint-disable-line
	}

	return await native_navigation(url, replace_state);
}

export function subsequent_fetch(resource, resolved, opts) {
	if (cache.size > 0) {
		const selector = build_selector(resource, opts);
		const cached = cache.get(selector);
		if (cached) {
			// https://developer.mozilla.org/en-US/docs/Web/API/Request/cache#value
			if (
				performance.now() < cached.ttl &&
				['default', 'force-cache', 'only-if-cached', undefined].includes(opts?.cache)
			) {
				return new Response(cached.body, cached.init);
			}

			cache.delete(selector);
		}
	}

	return DEV ? dev_fetch(resolved, opts) : window.fetch(resolved, opts);
}

export async function* read_stream(reader, delimiter) {
	let done = false;
	let buffer = '';
	const decoder = new TextDecoder();

	while (true) {
		let split = buffer.indexOf(delimiter);
		while (split !== -1) {
			yield buffer.slice(0, split);
			buffer = buffer.slice(split + delimiter.length);
			split = buffer.indexOf(delimiter);
		}

		if (done) {
			if (buffer) {
				yield buffer;
			}
			return;
		}

		const chunk = await reader.read();
		done = chunk.done;
		if (chunk.value) {
			buffer += decoder.decode(chunk.value, { stream: true });
		}

		if (done) {
			buffer += decoder.decode();
		}
	}
}

slice(start = 0, end = this.size, contentType = this.type) {
	// https://github.com/nodejs/node/blob/a5f3cd8cb5ba9e7911d93c5fd3ebc6d781220dd8/lib/internal/blob.js#L240
	if (start < 0) {
		start = Math.max(this.size + start, 0);
	} else {
		start = Math.min(start, this.size);
	}

	if (end < 0) {
		end = Math.max(this.size + end, 0);
	} else {
		end = Math.min(end, this.size);
	}
	const size = Math.max(end - start, 0);
	const file = new LazyFile(
		this.name,
		contentType,
		size,
		this.lastModified,
		this.#get_chunk,
		this.#offset + start
	);

	return file;
}

export function clarify_devalue_error(event, error) {
	if (error.path) {
		return (
			`Data returned from \`load\` while rendering ${event.route.id} is not serializable: ${error.message} (${error.path}). ` +
			`If you need to serialize/deserialize custom types, use transport hooks: https://svelte.dev/docs/kit/hooks#Universal-hooks-transport.`
		);
	}

	if (error.path === '') {
		return `Data returned from \`load\` while rendering ${event.route.id} is not a plain object`;
	}

	// belt and braces — this should never happen
	return error.message;
}

function generate_serverless_function({ builder, routes, patterns, name, exclude }) {
	const manifest = builder.generateManifest({
		relativePath: '../server',
		routes
	});

	const fn = generate_serverless_function_module(manifest);
	const config = generate_config_export(patterns, exclude);

	if (builder.hasServerInstrumentationFile()) {
		writeFileSync(`.netlify/functions-internal/${name}.mjs`, fn);
		builder.instrument({
			entrypoint: `.netlify/functions-internal/${name}.mjs`,
			instrumentation: '.netlify/server/instrumentation.server.js',
			start: `.netlify/functions-start/${name}.start.mjs`,
			module: {
				generateText: generate_traced_module(config)
			}
		});
	} else {
		writeFileSync(`.netlify/functions-internal/${name}.mjs`, `${fn}\n${config}`);
	}
}

function serve_prerendered() {
	const handler = serve(path.join(dir, 'prerendered'));

	return (req, res, next) => {
		let { pathname, search, query } = polka_url_parser(req);

		try {
			pathname = decodeURIComponent(pathname);
		} catch {
			// ignore invalid URI
		}

		if (prerendered.has(pathname)) {
			return handler?.(req, res, next);
		}

		// remove or add trailing slash as appropriate
		let location = pathname.at(-1) === '/' ? pathname.slice(0, -1) : pathname + '/';
		if (prerendered.has(location)) {
			if (query) location += search;
			res.writeHead(308, { location }).end();
		} else {
			void next();
		}
	};
}

async (file) => {
	const url = `${origin}/${file}`;
	const response = await fetch(url, {
		// we need to add a bypass header if the user has deployment protection enabled
		// see https://vercel.com/docs/deployment-protection/methods-to-bypass-deployment-protection/protection-bypass-automation
		headers: read_headers
	});

	if (!response.ok) {
		if (response.status === 401) {
			throw new Error(
				`Please enable Protection Bypass for Automation: https://svelte.dev/docs/kit/adapter-vercel#Troubleshooting-Deployment-protection`
			);
		}

		// belt and braces — not sure how we could end up here
		throw new Error(
			`read(...) failed: could not fetch ${url} (${response.status} ${response.statusText})`
		);
	}

	return response.body;
}

async function compress_file(file, format = 'gz') {
	const compress =
		format == 'br'
			? zlib.createBrotliCompress({
					params: {
						[zlib.constants.BROTLI_PARAM_MODE]: zlib.constants.BROTLI_MODE_TEXT,
						[zlib.constants.BROTLI_PARAM_QUALITY]: zlib.constants.BROTLI_MAX_QUALITY,
						[zlib.constants.BROTLI_PARAM_SIZE_HINT]: statSync(file).size
					}
				})
			: zlib.createGzip({ level: zlib.constants.Z_BEST_COMPRESSION });

	const source = createReadStream(file);
	const destination = createWriteStream(`${file}.${format}`);

	await pipe(source, compress, destination);
}

export function create_explicit_env_types(variables, relative, type) {
	const declarations = Object.entries(variables)
		.filter(([_, config]) => !!config.public === (type === 'public'))
		.map(([name, config]) => {
			const comment = config.description ? `${create_jsdoc(config.description)}\n` : '';
			const type = config.schema
				? `import('@sveltejs/kit/internal/types').StandardSchemaV1.InferOutput<typeof import('${relative}').variables.${name}.schema>`
				: 'string';
			return `${comment}export const ${name}: ${type};`;
		});

	return dedent`
		declare module '$app/env/${type}' {
			${declarations.join('\n') || `// no ${type} environment variables were defined`}
		}
	`;
}

({ content, filename }) => {
	if (!filename) return;

	const basename = path.basename(filename);
	if (basename.startsWith('+page.') || basename.startsWith('+layout.')) {
		const match = content.match(options_regex);
		if (match && match.index !== undefined && !should_ignore(content, match.index)) {
			const fixed = basename.replace('.svelte', '(.server).js/ts');

			const message =
				`\n${colors.bold().red(path.relative('.', filename))}\n` +
				`\`${match[1]}\` will be ignored — move it to ${fixed} instead. See https://svelte.dev/docs/kit/page-options for more information.`;

			if (!warned.has(message)) {
				console.log(message);
				warned.add(message);
			}
		}
	}
}

function find_overridden_config(config, resolved_config, enforced_config, path, out) {
	if (config == null || resolved_config == null) {
		return out;
	}

	for (const key in enforced_config) {
		if (typeof config === 'object' && key in config && key in resolved_config) {
			const enforced = enforced_config[key];

			if (enforced === true) {
				if (config[key] !== resolved_config[key]) {
					out.push(path + key);
				}
			} else {
				find_overridden_config(config[key], resolved_config[key], enforced, path + key + '.', out);
			}
		}
	}
	return out;
}

export function not_found(req, res, base) {
	const type = negotiate(req.headers.accept ?? '*', ['text/plain', 'text/html']);

	// special case — handle `/` request automatically
	if (req.url === '/' && type === 'text/html') {
		res.statusCode = 307;
		res.setHeader('location', base);
		res.end();
		return;
	}

	res.statusCode = 404;

	const prefixed = base + req.url;

	if (type === 'text/html') {
		res.setHeader('Content-Type', 'text/html');
		res.end(
			`The server is configured with a public base URL of ${escape_html(
				base
			)} - did you mean to visit <a href="${escape_html(prefixed, true)}">${escape_html(
				prefixed
			)}</a> instead?`
		);
	} else {
		res.end(
			`The server is configured with a public base URL of ${escape_html(
				base
			)} - did you mean to visit ${escape_html(prefixed)} instead?`
		);
	}
}

export function resolve(id, params) {
	if (!id.startsWith('/')) {
		throw new Error(
			`Cannot use \`resolve(...)\` with a non-absolute pathname or route ID (got "${id}"). ` +
				'`resolve` is only for internal pathnames and route IDs; external URLs should be used directly.'
		);
	}

	const resolved = resolve_route(id, /** @type {Record<string, string>} */ (params));

	if (relative) {
		const store = try_get_request_store();

		if (store && !store.state.prerendering?.fallback) {
			const after_base = store.event.url.pathname.slice(initial_base.length);
			const segments = after_base.split('/').slice(2);
			const prefix = segments.map(() => '..').join('/') || '.';

			return prefix + resolved;
		}
	}

	return base + resolved;
}

function update_refresh_value(
	{ __, refreshes, refreshes_key, cache, payload },
	value,
	is_immediate_refresh = false
) {
	const promise = Promise.resolve(value);

	if (!is_immediate_refresh) {
		cache[payload] = { serialize: true, data: promise };
	}

	if (__.id) {
		refreshes.set(refreshes_key, promise);
	}

	promise.catch(noop);

	// we return an immediately-resolving promise so that the `refresh()` signature is consistent,
	// but it doesn't delay anything if awaited inside a command. this way, people aren't
	// penalised if they do `await q1.refresh(); await q2.refresh()`
	return Promise.resolve();
}

export async function get_response(internals, payload, state, get_result) {
	// wait a beat, in case `myQuery().set(...)` or `myQuery().refresh()` is immediately called
	// eslint-disable-next-line @typescript-eslint/await-thenable
	await 0;

	const cache = get_cache(internals, state);
	const entry = (cache[payload] ??= {
		serialize: false,
		data: get_result()
	});

	entry.serialize ||= !!state.is_in_universal_load;

	if (state.is_in_render && internals.id) {
		const remote_key = create_remote_key(internals.id, payload);

		Promise.resolve(entry.data)
			.then((value) => {
				void unfriendly_hydratable(remote_key, () => stringify(value, state.transport));
			})
			.catch(noop);
	}

	return entry.data;
}

private async update(document: Document) {
    const uri = document.getURL();
    this.cancelStarted(uri);

    const tokenSource = new CancellationTokenSource();
    this.cancellationTokens.set(uri, tokenSource);

    const diagnostics = await this.getDiagnostics(
        { uri: document.getURL() },
        tokenSource.token
    );
    this.sendDiagnostics({
        uri: document.getURL(),
        diagnostics
    });

    tokenSource.dispose();

    if (this.cancellationTokens.get(uri) === tokenSource) {
        this.cancellationTokens.delete(uri);
    }
}

private searchConfigPathUpwards(path: string) {
    let currentDir = path;
    let nextDir = this.path.dirname(path);
    while (currentDir !== nextDir) {
        const configPath =
            findViteConfigInDirectory(this.fs, this.path, currentDir) ??
            findSvelteConfigInDirectory(
                this.fs,
                this.path,
                currentDir,
                this.loadSvelteConfigTs
            );
        if (configPath) {
            return configPath;
        }

        currentDir = nextDir;
        nextDir = this.path.dirname(currentDir);
    }
}

private tryGetConfigForDirectory(file: string, fromDirectory: string) {
    for (const ending of VITE_CONFIG_EXTENSIONS) {
        const configPath = this.path.join(fromDirectory, `vite.config.${ending}`);
        const config = this.configFiles.get(configPath);
        if (config) {
            this.filePathToConfigPath.set(file, configPath);
            return config;
        }
    }
    for (const ending of getSvelteConfigExtensions(this.loadSvelteConfigTs)) {
        const configPath = this.path.join(fromDirectory, `svelte.config.${ending}`);
        const config = this.configFiles.get(configPath);
        if (config) {
            this.filePathToConfigPath.set(file, configPath);
            return config;
        }
    }
}

getOriginalPosition(generatedPosition: Position): Position {
    if (this.parent) {
        generatedPosition = this.parent.getOriginalPosition(generatedPosition);
    }

    if (generatedPosition.line < 0) {
        return { line: -1, character: -1 };
    }

    const mapped = originalPositionFor(this.traceMap, {
        line: generatedPosition.line + 1,
        column: generatedPosition.character
    });

    if (!mapped) {
        return { line: -1, character: -1 };
    }

    if (mapped.line === 0) {
        Logger.debug('Got 0 mapped line from', generatedPosition, 'col was', mapped.column);
    }

    return {
        line: (mapped.line || 0) - 1,
        character: mapped.column || 0
    };
}

getGeneratedPosition(originalPosition: Position): Position {
    if (this.parent) {
        originalPosition = this.parent.getGeneratedPosition(originalPosition);
    }

    const mapped = generatedPositionFor(this.traceMap, {
        line: originalPosition.line + 1,
        column: originalPosition.character,
        source: this.sourceUri
    });

    if (!mapped) {
        return { line: -1, character: -1 };
    }

    const result = {
        line: (mapped.line || 0) - 1,
        character: mapped.column || 0
    };

    if (result.line < 0) {
        return result;
    }

    return result;
}

export function mapLocationLinkToOriginal(
    fragment: DocumentMapper,
    def: LocationLink
): LocationLink {
    return LocationLink.create(
        def.targetUri,
        fragment.getURL() === def.targetUri
            ? mapRangeToOriginal(fragment, def.targetRange)
            : def.targetRange,
        fragment.getURL() === def.targetUri
            ? mapRangeToOriginal(fragment, def.targetSelectionRange)
            : def.targetSelectionRange,
        def.originSelectionRange
            ? mapRangeToOriginal(fragment, def.originSelectionRange)
            : undefined
    );
}

export function positionAt(
    offset: number,
    text: string,
    lineOffsets = getLineOffsets(text)
): Position {
    offset = clamp(offset, 0, text.length);

    let low = 0;
    let high = lineOffsets.length;
    if (high === 0) {
        return Position.create(0, offset);
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const lineOffset = lineOffsets[mid];

        if (lineOffset === offset) {
            return Position.create(mid, 0);
        } else if (offset > lineOffset) {
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    // low is the least x for which the line offset is larger than the current offset
    // or array.length if no line offset is larger than the current offset
    const line = low - 1;
    return Position.create(line, offset - lineOffsets[line]);
}

getDiagnosticsForPullMode(
    document: Document,
    previousResultId: string | undefined
): FullDocumentDiagnosticReport | UnchangedDocumentDiagnosticReport {
    if (!this.featureEnabled('diagnostics')) {
        return {
            kind: 'full',
            items: []
        };
    }

    const resultId = document.version.toString();
    if (previousResultId === resultId) {
        return {
            kind: 'unchanged',
            resultId
        };
    }
    const diagnostics = this.getDiagnostics(document);
    return {
        kind: 'full',
        items: diagnostics,
        resultId
    };
}

getDocumentSymbols(document: Document): SymbolInformation[] {
    if (!this.featureEnabled('documentColors')) {
        return [];
    }

    const cssDocument = this.getCSSDoc(document);

    if (shouldExcludeDocumentSymbols(cssDocument)) {
        return [];
    }

    return this.getLanguageService(extractLanguage(cssDocument))
        .findDocumentSymbols(cssDocument, cssDocument.stylesheet)
        .map((symbol) => {
            if (!symbol.containerName) {
                return {
                    ...symbol,
                    // TODO: this could contain other things, e.g. style.myclass
                    containerName: 'style'
                };
            }

            return symbol;
        })
        .map((symbol) => mapSymbolInformationToOriginal(cssDocument, symbol));
}

getFoldingRanges(document: Document): FoldingRange[] {
    if (!document.styleInfo) {
        return [];
    }

    const cssDocument = this.getCSSDoc(document);
    if (shouldUseIndentBasedFolding(cssDocument.languageId)) {
        return this.nonSyntacticFolding(document, document.styleInfo);
    }

    return this.getLanguageService(extractLanguage(cssDocument))
        .getFoldingRanges(cssDocument)
        .map((range) => {
            const originalRange = mapRangeToOriginal(cssDocument, {
                start: { line: range.startLine, character: range.startCharacter ?? 0 },
                end: { line: range.endLine, character: range.endCharacter ?? 0 }
            });

            return {
                startLine: originalRange.start.line,
                endLine: originalRange.end.line,
                kind: range.kind
            };
        });
}

private getCSSDocAtPosition(document: Document, position: Position): CSSDocument | null {
    if (isInTag(position, document.styleInfo)) {
        return this.getCSSDoc(document);
    }

    if (
        isInTag(position, document.scriptInfo) ||
        isInTag(position, document.moduleScriptInfo) ||
        isInTag(position, document.templateInfo)
    ) {
        return null;
    }

    const styleInfo = extractStyleTagAtOffset(
        document.getText(),
        document.offsetAt(position),
        document.html
    );

    return styleInfo ? new CSSDocument(document, this.cssLanguageServices, styleInfo) : null;
}
